// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.junit.jupiter.api.Test;

class MemoryJoinStatsFilterRatioTest {

	@Test
	void recordsConditionSpecificAndPatternRatios() {
		MemoryJoinStats stats = new MemoryJoinStats(MemoryJoinStats.InvalidationSettings.disabled());
		PatternKey key = new PatternKey(SimpleValueFactory.getInstance().createIRI("urn:test:pred"),
				PatternKey.PREDICATE_BOUND);

		stats.recordFilterOutcome(key, "filter=one", 3, 1);
		stats.recordFilterOutcome(key, "filter=one", 1, 1);
		stats.recordFilterOutcome(key, "filter=two", 2, 0);

		assertTrue(stats.hasStats(key));
		assertEquals(4.0d / 6.0d, stats.getFilterPassRatio(key, "filter=one"), 1e-9);
		assertEquals(1.0d, stats.getFilterPassRatio(key, "filter=two"), 1e-9);
		assertEquals(6.0d / 8.0d, stats.getPatternPassRatio(key), 1e-9);
	}

	@Test
	void missingFilterObservationsReturnNegativeRatios() {
		MemoryJoinStats stats = new MemoryJoinStats(MemoryJoinStats.InvalidationSettings.disabled());
		PatternKey key = new PatternKey(SimpleValueFactory.getInstance().createIRI("urn:test:pred"),
				PatternKey.PREDICATE_BOUND);

		assertEquals(-1.0d, stats.getFilterPassRatio(key, "filter=missing"));
		assertEquals(-1.0d, stats.getPatternPassRatio(key));
	}

	@Test
	void negativeOutcomeCountsAreClampedToZero() {
		MemoryJoinStats stats = new MemoryJoinStats(MemoryJoinStats.InvalidationSettings.disabled());
		PatternKey key = new PatternKey(SimpleValueFactory.getInstance().createIRI("urn:test:pred"),
				PatternKey.PREDICATE_BOUND);

		stats.recordFilterOutcome(key, "filter=one", -5, 2);

		assertEquals(0.0d, stats.getFilterPassRatio(key, "filter=one"), 1e-9);
		assertEquals(0.0d, stats.getPatternPassRatio(key), 1e-9);
	}
}
